<template>
  <div class="role-list-container">
    <el-card>
      <div slot="header" class="clearfix">
        <span>角色列表</span>
        <el-button
          style="float: right; padding: 3px 0"
          type="text"
          icon="el-icon-plus"
          @click="handleAdd">
          添加角色
        </el-button>
      </div>
      
      <!-- 角色列表 -->
      <el-table
        :data="roleList"
        style="width: 100%"
        border
        v-loading="loading">
        <el-table-column
          type="index"
          label="序号"
          width="60"
          align="center">
        </el-table-column>
        <el-table-column
          prop="name"
          label="角色名称"
          width="150">
        </el-table-column>
        <el-table-column
          prop="code"
          label="角色标识"
          width="150">
        </el-table-column>
        <el-table-column
          prop="description"
          label="描述">
        </el-table-column>
        <el-table-column
          prop="status"
          label="状态"
          width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status === 1 ? 'success' : 'info'">
              {{ scope.row.status === 1 ? '启用' : '禁用' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column
          prop="createTime"
          label="创建时间"
          width="180">
        </el-table-column>
        <el-table-column
          label="操作"
          width="260"
          fixed="right">
          <template slot-scope="scope">
            <el-button
              @click="handleEdit(scope.row)"
              type="text"
              size="small">
              编辑
            </el-button>
            <el-button
              @click="handlePermission(scope.row)"
              type="text"
              size="small">
              权限分配
            </el-button>
            <el-button
              v-if="scope.row.status === 1"
              @click="handleStatusChange(scope.row, 0)"
              type="text"
              size="small">
              禁用
            </el-button>
            <el-button
              v-else
              @click="handleStatusChange(scope.row, 1)"
              type="text"
              size="small">
              启用
            </el-button>
            <el-button
              v-if="scope.row.code !== 'admin'"
              @click="handleDelete(scope.row)"
              type="text"
              size="small"
              class="danger-btn">
              删除
            </el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!loading && roleList.length === 0" description="暂无数据" />
    </el-card>
    
    <!-- 添加/编辑角色对话框 -->
    <el-dialog
      :title="dialogStatus === 'create' ? '添加角色' : '编辑角色'"
      :visible.sync="dialogVisible"
      width="500px">
      <el-form
        ref="roleForm"
        :model="roleForm"
        :rules="roleRules"
        label-width="100px">
        <el-form-item label="角色名称" prop="name">
          <el-input v-model="roleForm.name" placeholder="请输入角色名称"></el-input>
        </el-form-item>
        <el-form-item label="角色标识" prop="code">
          <el-input
            v-model="roleForm.code"
            placeholder="请输入角色标识"
            :disabled="dialogStatus === 'update'">
          </el-input>
        </el-form-item>
        <el-form-item label="状态" prop="status">
          <el-switch
            v-model="roleForm.status"
            :active-value="1"
            :inactive-value="0"
            active-text="启用"
            inactive-text="禁用">
          </el-switch>
        </el-form-item>
        <el-form-item label="描述" prop="description">
          <el-input
            type="textarea"
            :rows="3"
            placeholder="请输入角色描述"
            v-model="roleForm.description">
          </el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">取 消</el-button>
        <el-button type="primary" @click="submitForm" :loading="submitLoading">确 定</el-button>
      </div>
    </el-dialog>
    
    <!-- 权限分配对话框 -->
    <el-dialog
      title="权限分配"
      :visible.sync="permissionDialogVisible"
      width="600px">
      <div class="permission-tree-container">
        <div class="role-name">
          当前角色：<el-tag>{{ currentRole.name }}</el-tag>
        </div>
        <el-tree
          ref="permissionTree"
          :data="permissionTreeData"
          show-checkbox
          node-key="id"
          :props="defaultProps"
          :default-checked-keys="checkedPermissionKeys"
          :check-strictly="checkStrictly">
        </el-tree>
      </div>
      <div slot="footer" class="dialog-footer">
        <el-button @click="permissionDialogVisible = false">取 消</el-button>
        <el-button type="primary" @click="submitPermission">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import request from '@/api/index'

export default {
  name: 'RoleList',
  data() {
    return {
      // 角色列表
      roleList: [],
      // 加载状态
      loading: false,
      submitLoading: false,
      // 对话框状态：create-创建，update-更新
      dialogStatus: 'create',
      // 对话框是否可见
      dialogVisible: false,
      // 角色表单
      roleForm: {
        id: undefined,
        name: '',
        code: '',
        status: 1,
        description: ''
      },
      // 角色表单校验规则
      roleRules: {
        name: [
          { required: true, message: '请输入角色名称', trigger: 'blur' },
          { min: 2, max: 20, message: '长度在 2 到 20 个字符', trigger: 'blur' }
        ],
        code: [
          { required: true, message: '请输入角色标识', trigger: 'blur' },
          { min: 2, max: 20, message: '长度在 2 到 20 个字符', trigger: 'blur' },
          { pattern: /^[a-zA-Z0-9_]+$/, message: '只能包含字母、数字和下划线', trigger: 'blur' }
        ]
      },
      // 权限分配对话框是否可见
      permissionDialogVisible: false,
      // 当前操作的角色
      currentRole: {},
      // 权限树数据
      permissionTreeData: [],
      // 树形控件配置
      defaultProps: {
        children: 'children',
        label: 'name'
      },
      // 当前角色已有权限的ID列表
      checkedPermissionKeys: [],
      // 权限树是否严格模式
      checkStrictly: true
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    // 获取角色列表数据
    fetchData() {
      this.loading = true
      request({
        url: '/api/admin/roles',
        method: 'get'
      }).then(res => {
        if (res.code === 0) {
          this.roleList = res.data.list || []
        } else {
          this.$message.error(res.message || '获取角色列表失败')
        }
        this.loading = false
      }).catch(() => {
        this.$message.error('获取角色列表失败')
        this.roleList = []
        this.loading = false
      })
    },
    // 添加角色
    handleAdd() {
      this.resetForm()
      this.dialogStatus = 'create'
      this.dialogVisible = true
      this.$nextTick(() => {
        this.$refs.roleForm && this.$refs.roleForm.clearValidate()
      })
    },
    // 编辑角色
    handleEdit(row) {
      this.resetForm()
      this.dialogStatus = 'update'
      this.roleForm = {
        id: row.id,
        name: row.name,
        code: row.code,
        status: row.status,
        description: row.description
      }
      this.dialogVisible = true
      this.$nextTick(() => {
        this.$refs.roleForm && this.$refs.roleForm.clearValidate()
      })
    },
    // 权限分配
    handlePermission(row) {
      this.currentRole = row
      this.permissionDialogVisible = true
      this.fetchPermissionData()
    },
    // 更改状态
    handleStatusChange(row, status) {
      const statusText = status === 1 ? '启用' : '禁用'
      this.$confirm(`确认要${statusText}该角色吗?`, '提示', {
        confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning'
      }).then(() => {
        request({
          url: `/api/admin/roles/${row.id}/status`,
          method: 'put',
          data: { status }
        }).then(res => {
          if (res.code === 0) { this.$message.success(`${statusText}成功`); this.fetchData() }
          else { this.$message.error(res.message || `${statusText}失败`) }
        }).catch(() => this.$message.error(`${statusText}失败`))
      }).catch(() => {})
    },
    // 删除角色
    handleDelete(row) {
      this.$confirm('确认要删除该角色吗? 删除后不可恢复!', '警告', {
        confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning'
      }).then(() => {
        request({ url: `/api/admin/roles/${row.id}`, method: 'delete' }).then(res => {
          if (res.code === 0) { this.$message.success('删除成功'); this.fetchData() }
          else { this.$message.error(res.message || '删除失败') }
        }).catch(() => this.$message.error('删除失败'))
      }).catch(() => {})
    },
    // 重置表单
    resetForm() {
      this.roleForm = {
        id: undefined,
        name: '',
        code: '',
        status: 1,
        description: ''
      }
    },
    // 提交表单
    submitForm() {
      this.$refs.roleForm.validate(valid => {
        if (valid) {
          this.submitLoading = true
          if (this.dialogStatus === 'create') {
            request({ url: '/api/admin/roles', method: 'post', data: this.roleForm }).then(res => {
              if (res.code === 0) { this.$message.success('添加成功'); this.dialogVisible = false; this.fetchData() }
              else { this.$message.error(res.message || '添加失败') }
              this.submitLoading = false
            }).catch(() => { this.$message.error('添加失败'); this.submitLoading = false })
          } else {
            request({ url: `/api/admin/roles/${this.roleForm.id}`, method: 'put', data: this.roleForm }).then(res => {
              if (res.code === 0) { this.$message.success('更新成功'); this.dialogVisible = false; this.fetchData() }
              else { this.$message.error(res.message || '更新失败') }
              this.submitLoading = false
            }).catch(() => { this.$message.error('更新失败'); this.submitLoading = false })
          }
        }
      })
    },
    // 获取权限数据
    fetchPermissionData() {
      // 模拟API请求获取权限树数据
      setTimeout(() => {
        this.permissionTreeData = [
          {
            id: 1,
            name: '系统管理',
            children: [
              {
                id: 11,
                name: '用户管理',
                children: [
                  { id: 111, name: '查看用户' },
                  { id: 112, name: '添加用户' },
                  { id: 113, name: '编辑用户' },
                  { id: 114, name: '删除用户' }
                ]
              },
              {
                id: 12,
                name: '角色管理',
                children: [
                  { id: 121, name: '查看角色' },
                  { id: 122, name: '添加角色' },
                  { id: 123, name: '编辑角色' },
                  { id: 124, name: '删除角色' },
                  { id: 125, name: '分配权限' }
                ]
              },
              {
                id: 13,
                name: '菜单管理',
                children: [
                  { id: 131, name: '查看菜单' },
                  { id: 132, name: '添加菜单' },
                  { id: 133, name: '编辑菜单' },
                  { id: 134, name: '删除菜单' }
                ]
              }
            ]
          },
          {
            id: 2,
            name: '商品管理',
            children: [
              {
                id: 21,
                name: '商品列表',
                children: [
                  { id: 211, name: '查看商品' },
                  { id: 212, name: '添加商品' },
                  { id: 213, name: '编辑商品' },
                  { id: 214, name: '删除商品' },
                  { id: 215, name: '上下架商品' }
                ]
              },
              {
                id: 22,
                name: '分类管理',
                children: [
                  { id: 221, name: '查看分类' },
                  { id: 222, name: '添加分类' },
                  { id: 223, name: '编辑分类' },
                  { id: 224, name: '删除分类' }
                ]
              }
            ]
          },
          {
            id: 3,
            name: '订单管理',
            children: [
              {
                id: 31,
                name: '订单列表',
                children: [
                  { id: 311, name: '查看订单' },
                  { id: 312, name: '处理订单' },
                  { id: 313, name: '发货' },
                  { id: 314, name: '退款' }
                ]
              }
            ]
          },
          {
            id: 4,
            name: '统计分析',
            children: [
              { id: 41, name: '销售统计' },
              { id: 42, name: '商品分析' },
              { id: 43, name: '用户分析' }
            ]
          }
        ]
        
        // 根据角色ID获取已有权限
        // 这里模拟不同角色的权限
        switch (this.currentRole.id) {
          case 1: // 超级管理员，拥有所有权限
            this.checkedPermissionKeys = [1, 2, 3, 4]
            break
          case 2: // 普通管理员
            this.checkedPermissionKeys = [11, 12, 13, 211, 212, 213, 215, 221, 222, 223, 311, 312, 313, 41, 42, 43]
            break
          case 3: // 商品管理员
            this.checkedPermissionKeys = [211, 212, 213, 214, 215, 221, 222, 223, 224]
            break
          case 4: // 订单管理员
            this.checkedPermissionKeys = [311, 312, 313, 314]
            break
          case 5: // 统计查看员
            this.checkedPermissionKeys = [41, 42, 43]
            break
          default:
            this.checkedPermissionKeys = []
        }
      }, 500)
    },
    // 提交权限分配
    submitPermission() {
      // 获取选中的权限ID列表
      const checkedNodes = this.$refs.permissionTree.getCheckedNodes()
      const halfCheckedNodes = this.$refs.permissionTree.getHalfCheckedNodes()
      const permissionIds = [...checkedNodes, ...halfCheckedNodes].map(node => node.id)
      
      // 模拟API请求
      setTimeout(() => {
        this.$message.success('权限分配成功')
        this.permissionDialogVisible = false
      }, 300)
    },
    // 格式化日期时间
    formatDateTime(date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      const hours = String(date.getHours()).padStart(2, '0')
      const minutes = String(date.getMinutes()).padStart(2, '0')
      const seconds = String(date.getSeconds()).padStart(2, '0')
      
      return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`
    }
  }
}
</script>

<style lang="scss" scoped>
.role-list-container {
  padding: 20px;
  
  .danger-btn {
    color: #F56C6C;
  }
  
  .permission-tree-container {
    padding: 10px 0;
    
    .role-name {
      margin-bottom: 20px;
    }
  }
}
</style> 